const e=[{id:"series_word_search",title:"Word Search Wonders",description:"Master the art of vocabulary with 20 levels of hidden word puzzles!",coverImage:"/series/word-search-cover.webp",price:0,difficulty:"Beginner",gameCount:20,unlockedByDefault:!0,accentColor:"#f472b6"},{id:"series_retro_arcade",title:"Retro Arcade Classics",description:"Rebuild the classics! From Snake to Space Invaders.",coverImage:"/series/retro-arcade-cover.webp",price:500,difficulty:"Intermediate",gameCount:15,accentColor:"#6366f1"},{id:"series_platformer_pro",title:"Platformer Paradise",description:"Level design, gravity, and power-ups. Build your own Mario-style world!",coverImage:"/series/platformer-pro-cover.webp",price:1e3,difficulty:"Pro",gameCount:12,accentColor:"#fbbf24"},{id:"series_retro_racer",title:"Retro Racer Academy",description:"Dodge traffic, collect stars, and learn collision avoidance logic!",coverImage:"/series/retro-racer-cover.png",price:300,difficulty:"Intermediate",gameCount:15,accentColor:"#10b981"},{id:"series_maze_runner",title:"Code Maze Runner",description:"Help the robot navigate the maze! Drag and drop logic blocks to learn sequencing and loops.",coverImage:"/series/maze-runner-cover.png",price:150,difficulty:"Beginner",gameCount:10,accentColor:"#8b5cf6"}],t=[{id:"m1_hello",level:1,pathway:"Fundamentals",name:"First Hello",description:"Teach the mascot to greet the world with its very first spoken word.",objective:'Drag a "Say" block into the workspace and make the mascot say "Hello World!"',steps:["Click the 🤖 Mascot category in the toolbox on the left.","Drag the 🗣️ Say block into the workspace.","Click the text inside the block and type: Hello World!","Press the ▶ Run Code button and watch the mascot speak!"],hints:["Open the 🤖 Mascot category — it's the first one in the toolbox!","Drag the block with 🗣️ Say on it into the big workspace area.","Double-click the text inside the block to edit it."],xpReward:150,difficulty:"easy",requiredBlocks:["mascot_speak"],minBlocks:1,briefing:"Welcome to the Lab, Engineer! I'm Byte, your coding assistant. Let's start with something simple — teach me to talk! Drag the 'Say' block and make me say Hello World!"},{id:"m2_rhythm",level:2,pathway:"Fundamentals",name:"Rhythm Master",description:"Build a timed sequence of actions — the foundation of all programming logic.",objective:"Make the mascot wave, pause for 2 seconds, then blink — all in order.",steps:["Drag a 👋 Wave Hand block into the workspace.","Below it, drag a 🕐 Wait block and set it to 2 seconds.","Below the wait, drag a 👁️ Blink Eyes block.","Press ▶ Run Code — all three should run in order!"],hints:["All three blocks are in the 🤖 Mascot category.","Blocks run top-to-bottom, so order matters — Wave first, then Wait, then Blink.","The Wait block has a number you can change — set it to 2."],xpReward:250,difficulty:"easy",requiredBlocks:["mascot_wave","mascot_wait","mascot_blink"],minBlocks:3,briefing:"Great job on Mission 1! Now let's learn about timing. Computers can do actions in a sequence — one after another. Build me a wave, a pause, and a blink!"},{id:"m3_loop",level:3,pathway:"Fundamentals",name:"The Loop Expert",description:"Computers are great at repeating tasks. Learn how loops save you from copying blocks!",objective:"Use a Repeat block to make the mascot wave exactly 3 times without placing 3 separate wave blocks.",steps:["Open the 🔄 Loops category and drag a Repeat block into the workspace.","Click the number on the Repeat block and change it to 3.","Open 🤖 Mascot and drag a Wave block inside the Repeat block.","Press ▶ Run — the mascot should wave 3 times!"],hints:["The Repeat block is in the 🔄 Loops category.","Drag the Wave block so it snaps *inside* the mouth of the Repeat block.","You only need ONE Wave block — the loop does the repeating for you!"],xpReward:400,difficulty:"medium",requiredBlocks:["controls_repeat_ext","mascot_wave"],minBlocks:2,briefing:"Mission 3 unlocked! Here's a secret engineers use: instead of writing the same action 100 times, we use LOOPS. They're like a magic repeat button. Let's try it!"},{id:"m4_vars",level:4,pathway:"Fundamentals",name:"Variable Vault",description:"Variables are like labeled boxes that store information your program can use later.",objective:'Create a variable called "score", set it to 10, then make the mascot announce the score.',steps:['Open 📦 Variables, click "Create variable…", and name it "score".','Drag a "set score to" block into the workspace.',"From 📦 Variables or Math, attach the number 10 to the set block.","Open 🤖 Mascot, drag a Say block below the set block.",'From 📦 Variables, drag the "score" pill into the Say block text slot.','Press ▶ Run — the mascot should say "10"!'],hints:["Click 'Create variable...' at the top of the Variables category to make a new one.","The 'set score to' block stores a value in your variable.","Drag the orange 'score' pill block into the Say block to print its value."],xpReward:500,difficulty:"medium",requiredBlocks:["variables_set","math_number","mascot_speak"],minBlocks:3,briefing:"You're getting really good! Now let's learn about Variables — the backbone of every program. Think of them like a sticky note where you can write down a number and read it later."},{id:"mobile_1",level:1,pathway:"Mobile App Dev",name:"App Screen 101",description:"Every app starts with a screen. Design your first mobile interface.",objective:'Build a Welcome screen with a title label and a "Start" button.',steps:['Drag a Screen block and set its name to "Welcome".','Add a Label block inside the screen with text "Welcome to My App!".','Add a Button block with the label "Start".',"Run your project to preview the screen layout."],hints:["All UI blocks are in the 📱 Mobile category.","Blocks nested inside a Screen block become part of that screen.","Set the button color to blue using the Button properties."],xpReward:300,difficulty:"easy",requiredBlocks:["mobile_screen","mobile_button"],minBlocks:3,briefing:"Welcome to Mobile App Dev! Every great app starts with a screen. Today you'll design your very first one. Think of yourself as a real app developer!"},{id:"mobile_2",level:2,pathway:"Mobile App Dev",name:"Touch Interaction",description:"Make your app respond when users tap things.",objective:"Change the background color to green when the Start button is tapped.",steps:['Add an "On Button Click" event block connected to your Start button.','Inside the event, add a "Set Background Color" block.',"Set the color value to green.","Run and tap the button to see the background change!"],hints:["Event blocks listen for user actions like taps.","The 'Set Background Color' block is in the UI actions category.","Connect the event block to the specific button by its name."],xpReward:450,difficulty:"medium",requiredBlocks:["on_click","set_bg_color"],minBlocks:2,briefing:"Apps aren't just pretty screens — they react to you! Today you'll make your app change when someone taps a button. This is called an Event."},{id:"mobile_3",level:3,pathway:"Mobile App Dev",name:"Remember Me",description:"Great apps remember their users. Use local storage to save data on the device.",objective:"Save the user's name to the phone's local database and load it back on startup.",steps:["Add a Text Input block to collect the user name.",'Add a "Save to Database" block using the key "username".','On app start, add a "Load from Database" block with the same key.',"Display the loaded name in a Label block.","Run and enter your name — it should reappear when you restart!"],hints:["The Save and Load blocks use a 'key' like a label on a jar.","Always use the same key name to save and load the same data.","Wrap the Load block in an 'On App Start' event."],xpReward:650,difficulty:"hard",requiredBlocks:["db_save","text_input"],minBlocks:4},{id:"desktop_1",level:1,pathway:"Desktop App Dev",name:"Window Creator",description:"Desktop apps live inside windows. Create and configure your first application window.",objective:'Open a 600×400 window with the title "My First App" and a white background.',steps:['Drag a "Create Window" block into the workspace.',"Set the width to 600 and height to 400.",'Set the window title to "My First App".','Add a "Set Background" block and choose white.',"Run to see your window appear!"],hints:["The Create Window block is your starting point — like opening a blank canvas.","Width and height are measured in pixels.","The title appears in the bar at the top of the window."],xpReward:300,difficulty:"easy",requiredBlocks:["desktop_window","set_title"],minBlocks:2,briefing:"Desktop app development is like building a house — you start with the walls (the window) before adding furniture. Let's build your first window!"},{id:"desktop_2",level:2,pathway:"Desktop App Dev",name:"The Menu Bar",description:"Professional apps have menus. Build a File menu with working actions.",objective:'Create a "File" menu with an "Open" option and an "Exit" option that closes the app.',steps:['Drag a "Create Menu Bar" block.','Add a "File" menu to the menu bar.','Add "Open" as a menu item inside File.','Add "Exit" as a second menu item.','Connect an "Exit App" action to the Exit item.',"Run and click File → Exit to close!"],hints:["Menu items go inside a Menu, which goes inside the Menu Bar.","Actions are attached to menu items using 'On Click' connectors.","The Exit App block immediately closes your program."],xpReward:500,difficulty:"medium",requiredBlocks:["desktop_menu","menu_item"],minBlocks:3},{id:"web_1",level:1,pathway:"Web App Dev",name:"Your First Webpage",description:"Every website starts with HTML. Build a simple page with a heading and a clickable link.",objective:'Create a webpage with an H1 heading saying "Kone Kids Rocks!" and a link to google.com.',steps:['Drag a "Heading" block and set the level to H1.','Type "Kone Kids Rocks!" as the heading text.','Drag a "Link" block below it.','Set the link URL to https://google.com and display text to "Visit Google".',"Run to preview your webpage!"],hints:["H1 is the biggest, most important heading on a page.","A link needs both a URL (where it goes) and display text (what you see).","Always start URLs with https://"],xpReward:300,difficulty:"easy",requiredBlocks:["web_link","web_text"],minBlocks:2,briefing:"The web is built from pages connected by links. Today you'll build your very first webpage — a heading and a link. Every website you've ever visited started exactly like this!"},{id:"web_2",level:2,pathway:"Web App Dev",name:"Style Wizard",description:"CSS makes websites beautiful. Add styles to make your page stand out.",objective:"Apply a neon glow effect to your H1 heading and set the page background to dark navy.",steps:['Add a "Set Page Background" block and choose color #0f172a.','Add a "Style Element" block targeting your H1.',"Set the text color to #38bdf8.","Enable the text-shadow / glow property.","Run and see your neon heading glow!"],hints:["Colors can be set using hex codes like #0f172a.","text-shadow creates a glow effect around text.","Target your element by its type: h1."],xpReward:450,difficulty:"medium",requiredBlocks:["web_style","css_neon"],minBlocks:2},{id:"game_1",level:1,pathway:"Game Dev",name:"Gravity Guard",description:"All great games have physics. Add gravity to your character and watch it fall!",objective:"Create a game scene, add the mascot as a character, and apply gravity so it falls to the floor.",steps:['Drag a "Create Scene" block and set size to 800×400.','Add a "Create Character" block and choose the mascot sprite.','Add a "Set Gravity" block and set gravity to 9.8.','Add a "Floor" platform at the bottom of the scene.',"Run and watch the mascot fall to the floor!"],hints:["Gravity pulls things downward — the higher the number, the faster it falls.","A Floor platform stops the character from falling forever.","Characters need physics enabled to be affected by gravity."],xpReward:400,difficulty:"medium",requiredBlocks:["game_physics","game_gravity"],minBlocks:3,briefing:"Game Dev time! Before you can make a game, you need to understand physics. Today we'll add gravity — the force that makes things fall. Every platformer game uses this!"},{id:"game_2",level:2,pathway:"Game Dev",name:"Hero Jump",description:"A character that can jump is the heart of every platformer game.",objective:"Make the mascot jump when the spacebar is pressed, with a realistic arc.",steps:['Add an "On Key Press" block and set it to Space.','Inside the event, add an "Apply Force" block pointing upward.',"Set the force to 500 to get a good jump height.","Add a cooldown so you can't jump mid-air (only when touching the floor).","Run and press Space to jump!"],hints:["Apply Force pushes the character in a direction instantly.","Upward force in most engines is negative Y (pointing up the screen).","Check if the character isOnGround before allowing a jump."],xpReward:550,difficulty:"medium",requiredBlocks:["on_key_press","character_jump"],minBlocks:3},{id:"game_3",level:3,pathway:"Game Dev",name:"Star Collector",description:"Every game needs a goal. Add collectible stars and a score counter.",objective:"Spawn 5 stars on the scene. When the mascot touches a star, add 10 to the score and remove the star.",steps:['Add a "Spawn Objects" block to place 5 star sprites at random positions.','Add an "On Collision" block between the character and star objects.','Inside the collision, add an "Update Score" block adding +10.','Add a "Remove Object" block to delete the collected star.','Display the score in the top corner using a "Score Display" block.',"Run and collect all stars to win!"],hints:["Collision detection triggers when two objects overlap.","Random positions make each game run feel different!","Destroy/remove the star after collection so it can't be collected twice."],xpReward:750,difficulty:"hard",requiredBlocks:["on_collision","update_score"],minBlocks:5},{id:"ds_1",level:1,pathway:"Data Science (AI 4 Kids)",name:"Data Detective",description:"Data scientists find patterns in numbers. Solve your first data puzzle!",objective:"Create a list of 6 numbers, sort it from smallest to largest, and display the result.",steps:["Create a List block and add these numbers: 42, 7, 15, 3, 99, 21.",'Add a "Sort List" block set to ascending order.',"Connect the list to the sort block.",'Add a "Display List" block to show the sorted result.',"Run and verify the numbers are in order!"],hints:["Lists store multiple values in one place.","Ascending means smallest first, descending means largest first.","The sorted list should be: 3, 7, 15, 21, 42, 99."],xpReward:350,difficulty:"easy",requiredBlocks:["list_sort","math_number"],minBlocks:3,briefing:"Welcome to Data Science! Data scientists are like detectives — they look at numbers and find hidden patterns. Today's mission: organize a messy list of numbers!"},{id:"ds_2",level:2,pathway:"Data Science (AI 4 Kids)",name:"Chart Captain",description:"A picture is worth a thousand numbers. Visualize data as a bar chart.",objective:"Create a bar chart showing the favorite colors of a class of 10 students.",steps:["Create a data set: Blue=4, Red=2, Green=3, Yellow=1.",'Add a "Create Chart" block and set type to Bar Chart.',"Connect each color and its count to the chart.",'Set the chart title to "Favorite Colors in Our Class".',"Run to display the finished chart!"],hints:["Each bar in a bar chart represents one category.","The height of the bar shows the count for that category.","Give your chart a title so people know what it's about."],xpReward:550,difficulty:"medium",requiredBlocks:["draw_chart","chart_bar"],minBlocks:4},{id:"ml_1",level:1,pathway:"ML (AI 4 Kids)",name:"Trainer Pro",description:"Machine Learning models learn from examples. Teach your first AI to recognise shapes!",objective:"Train an AI model with 3 circles and 3 squares, then test it on a new shape.",steps:['Add 3 Circle shapes to the Training Set and label them "Circle".','Add 3 Square shapes to the Training Set and label them "Square".','Add a "Train Model" block and run it.','Add a "Test Model" block with a new circle shape.',"Display whether the model correctly identifies it!"],hints:["Training data is the examples you give the AI to learn from.","More training examples = smarter AI!","Labels are the correct answers the AI learns to predict."],xpReward:450,difficulty:"medium",requiredBlocks:["ml_train","shape_circle","shape_square"],minBlocks:4,briefing:"Machine Learning is how AIs learn — not from rules, but from EXAMPLES! You'll show the AI pictures of shapes, and it'll learn to tell them apart all on its own. Cool, right?"},{id:"ml_2",level:2,pathway:"ML (AI 4 Kids)",name:"Predictor",description:"A trained model can predict future data it has never seen before.",objective:"Use your trained shape model to classify 5 new mystery shapes and display the results.",steps:["Load the model you trained in Mission 1.","Create a list of 5 mystery shapes (mix of circles and squares).",'Loop through the list and run each shape through the "Predict" block.','Display each prediction: "Shape 1: Circle", "Shape 2: Square", etc.',"Check if all 5 predictions are correct!"],hints:["You can load a previously trained model using a 'Load Model' block.","Use a loop to run predictions on many shapes efficiently.","The Predict block returns the label your model thinks is correct."],xpReward:700,difficulty:"hard",requiredBlocks:["ml_predict","ml_model"],minBlocks:4},{id:"ml_3",level:3,pathway:"ML (AI 4 Kids)",name:"Traffic Officer",description:"Autonomous vehicles need to see! Train your AI to recognize traffic signs and direct the car.",objective:'Train the model to recognize "Stop" and "Go" signs, and program it to speak when they are detected.',steps:["Open the AI Studio and select the Landmarks or Gestures tab.",'Capture 3 training images for Class A and label it "Stop".','Capture 3 training images for Class B and label it "Go".','Click "Train Neural Network" to train your model.','Add a "When AI sees" block for "Stop" and make the mascot say "Brake! 🛑".','Add a "When AI sees" block for "Go" and make the mascot say "Drive! 🟢".',"Run the code and simulate the signs to test it!"],hints:["Labels are case-sensitive. Use 'Stop' and 'Go'.","Ensure you train the model before running the detection blocks.","The 'When AI sees' block is in the AI Hub category."],xpReward:900,difficulty:"medium",requiredBlocks:["on_class_detect","mascot_speak"],minBlocks:4,briefing:"Welcome to the Self-Driving Lab! Self-driving cars use computer vision to read traffic signs. Today you'll train a model to recognize 'Stop' and 'Go' signs, and program your mascot to act as the car's voice!"},{id:"ai_1",level:1,pathway:"AI (AI 4 Kids)",name:"Chatbot Builder",description:"Build your first AI chatbot that understands questions and replies intelligently.",objective:'Create a chatbot that responds to "How are you?" with "I am fine!" and "What is your name?" with "I am Byte!".',steps:['Add an "On User Input" block to receive messages.','Add an "If Text Contains" block checking for "How are you".','Inside the if, make the mascot say "I am fine!".','Add an else-if checking for "What is your name".','Make the mascot say "I am Byte!" in that branch.',"Run and type your questions to chat!"],hints:["The 'If Text Contains' block checks if a word is somewhere in the message.","You can chain multiple conditions with else-if blocks.","This is how real chatbots work — matching patterns to responses!"],xpReward:500,difficulty:"medium",requiredBlocks:["ai_input","logic_compare","mascot_speak"],minBlocks:4,briefing:"You're entering the AI Studio! Chatbots are everywhere — in your phone, on websites, in games. Today you'll build one from scratch. Your mascot will learn to hold a conversation!"},{id:"ai_2",level:2,pathway:"AI (AI 4 Kids)",name:"Visionary",description:"AI can see! Use computer vision to detect faces through the camera.",objective:"Activate the camera, detect when a face appears, and make the mascot react.",steps:['Add a "Start Camera" block to activate the webcam feed.','Add a "Detect Face" block to the live camera input.','Use an "If Face Detected" condition block.','Make the mascot say "I see a face! 👋" when a face is found.','Add an else: "No face detected yet…" when none is found.',"Run and wave at the camera!"],hints:["Computer vision means teaching a computer to understand images.","The camera must be started before you can detect anything.","Face detection works by looking for eyes, nose, and mouth patterns."],xpReward:800,difficulty:"hard",requiredBlocks:["camera_input","detect_face"],minBlocks:4},{id:"ai_3",level:3,pathway:"AI (AI 4 Kids)",name:"Smart Assistant",description:"Build a voice-activated smart home assistant that controls a virtual light!",objective:'Create a voice assistant that listens for "light on" to turn the green LED ON, and "light off" to turn it OFF.',steps:["Open the AI Studio and select the Emotions or Gestures tab.",'Capture 3 training images for Class A and label it "light on".','Capture 3 training images for Class B and label it "light off".',"Train the neural network.",'Add a "When AI sees" block for "light on" and plug in a "Set LED" block set to Green and ON.','Add a "When AI sees" block for "light off" and plug in a "Set LED" block set to Green and OFF.',"Run your code and trigger the commands to control the light!"],hints:["Type the labels exactly as 'light on' and 'light off' (lowercase).","The 'Set LED' block is in the Electronics category.","This simulates how smart speakers (like Alexa) control real appliances!"],xpReward:1e3,difficulty:"hard",requiredBlocks:["on_class_detect","led_state"],minBlocks:4,briefing:"Smart homes use voice recognition to control devices. Today you'll build your own assistant! You'll train the AI to recognize your commands and wire it to control a virtual LED light!"},{id:"robotics_1",level:1,pathway:"Robotics (Robotics 4 Kids)",name:"Motor Master",description:"Control real motors with code! Drive the virtual robot through an L-shaped path.",objective:"Drive the robot forward 2 seconds, turn right 1 second, then drive forward again and stop.",steps:["Drag a 🚜 Move Forward block and set duration to 2 seconds.","Below it, drag a 🔄 Turn Right block and set duration to 1 second.","Add another 🚜 Move Forward block for 1.5 seconds.","End with a 🛑 Stop Robot block.","Press ▶ Run and watch the robot trace an L-path!"],hints:["The robot moves based on time — longer duration = further distance.","Turning for 1 second at normal speed is roughly a 90° turn.","Always end with a Stop block so the robot doesn't keep running!"],xpReward:500,difficulty:"medium",requiredBlocks:["robot_move","robot_turn","robot_stop"],minBlocks:4,briefing:"Whoa — welcome to the Robotics Lab! See that virtual robot car? It responds to your code blocks. Today you'll drive it through a real path by programming its motors step by step!"},{id:"robotics_2",level:2,pathway:"Robotics (Robotics 4 Kids)",name:"Sensor Sentry",description:"Smart robots sense their environment. Program obstacle detection using the distance sensor.",objective:"Drive the robot forward and automatically stop when the distance sensor detects an object closer than 30 units.",steps:["Add a 🚜 Move Forward block set to 10 seconds (so it has time to detect).","Add a 🧠 Logic If block using the 📏 Distance Sensor as the condition.","Set the condition: if distance < 30, then stop.","Inside the if block, add 🛑 Stop Robot.",'Add a 🗣️ Say "Obstacle detected!" block after the stop.',"Run and watch the robot stop before hitting the wall!"],hints:["The Distance Sensor block returns the current distance to the nearest wall.","Use a Logic If block to make decisions based on the sensor reading.","Test with different distance thresholds to see how the robot reacts."],xpReward:700,difficulty:"hard",requiredBlocks:["robot_move","robot_distance","controls_if","robot_stop"],minBlocks:4,briefing:"You can drive the robot — now let's make it SMART! Real robots use sensors to avoid obstacles. You'll program the distance sensor to detect walls and brake automatically."},{id:"robotics_3",level:3,pathway:"Robotics (Robotics 4 Kids)",name:"Maze Runner",description:"A double-bend Z-maze. Navigate the narrow corridors to reach the target flag!",objective:"Drive the robot through the Z-maze to reach the checkered flag without hitting any walls.",steps:["Look at the Z-maze layout: you need to go Right, then Down, then Left, then Down, then Right.","Plan your moves: drive forward, turn right, drive forward, turn left, drive forward.","Add a 🚜 Move Forward block, then a 🔄 Turn block, and repeat.","Make sure you adjust the durations so you don't hit the walls!","End with a 🛑 Stop Robot block at the target."],hints:["The corridor width is narrow. Keep your movements precise.","A 90° turn is roughly 1 second at normal speed.","If you crash, press Reset Robot 🔄 and adjust your durations."],xpReward:900,difficulty:"medium",requiredBlocks:["robot_move","robot_turn","robot_stop"],minBlocks:6,briefing:"Welcome to the Maze Challenge! Navigating narrow pathways is a key skill for warehouse and logistics robots. Today, you'll write a program to guide our robot through a double-bend Z-maze!"},{id:"robotics_4",level:4,pathway:"Robotics (Robotics 4 Kids)",name:"Rescue Mission",description:"An obstacle blocks your path! Use the sensor to detect it, turn right, and bypass it.",objective:"Drive forward, detect the blocking wall with your sensor, turn right to bypass it, and reach the flag.",steps:["Start driving forward towards the obstacle.","Use a 🧠 Logic If block with the 📏 Distance Sensor to detect when the obstacle is close (< 40).","Inside the if block, stop the robot, turn right, and then drive forward to bypass the wall.","Turn left after bypassing and drive up to the target flag.","Ensure the robot reaches the flag safely without crashing."],hints:["Use 'if distance < 40' to detect the wall before you crash.","After turning right, you need to drive forward about 2 seconds to clear the obstacle.","Then turn left (90°) and drive forward to reach the goal."],xpReward:1200,difficulty:"hard",requiredBlocks:["robot_move","robot_turn","robot_distance","controls_if","robot_stop"],minBlocks:6,briefing:"Emergency! An unexpected obstacle is blocking the main path. You must write a program that uses the distance sensor to detect the block, turn right to take the detour, and reach the safe zone!"},{id:"electronics_1",level:1,pathway:"Electronics (Robotics 4 Kids)",name:"LED Blinker",description:"Connect and control a virtual light-emitting diode (LED) to create a visual signal.",objective:"Make the green LED turn on, wait for 1 second, then turn off.",steps:["Drag a ⚡ Set LED block into the workspace.","Set the color to Green and state to ON.","Below it, drag a 🕐 Wait block for 1 second.","Below the wait, drag another ⚡ Set LED block set to Green and OFF.","Press ▶ Run Code and watch the virtual LED blink!"],hints:["Open the ⚡ Electronics category in the toolbox.","Make sure you set the first block to ON and the second to OFF.","The Wait block is in the 🔄 Loops category."],xpReward:400,difficulty:"easy",requiredBlocks:["led_state","mascot_wait"],minBlocks:3,briefing:"Welcome to the Electronics Lab! Today, you'll learn how to control hardware using code. Let's start by lighting up our first LED!"},{id:"electronics_2",level:2,pathway:"Electronics (Robotics 4 Kids)",name:"Traffic Signal",description:"Build a mini traffic signal using Red, Yellow, and Green lights in sequence.",objective:"Program the Red light for 2 seconds, Yellow for 1 second, then Green for 2 seconds.",steps:["Turn Red LED ON, wait 2 seconds, then turn Red LED OFF.","Turn Yellow LED ON, wait 1 second, then turn Yellow LED OFF.","Turn Green LED ON, wait 2 seconds, then turn Green LED OFF.","Press ▶ Run Code to activate the automated traffic controller!"],hints:["Sequence your blocks from top to bottom.","Remember to turn each light OFF before starting the next one.","Use 3 different Set LED blocks and 3 Wait blocks."],xpReward:600,difficulty:"medium",requiredBlocks:["led_state","mascot_wait"],minBlocks:6,briefing:"Brilliant! Now let's build something you see every day on the streets of Accra — a traffic light system! You'll control three separate LEDs in sequence."}];export{t as CODING_MISSIONS,e as GAME_SERIES};
